import { useRef } from 'react';
import { CSSTransition } from 'react-transition-group';
import { CSSTransitionProps } from 'react-transition-group/CSSTransition';

export type AnimationName =
  | 'zoom-center-top'
  | 'zoom-center-bottom'
  | 'zoom-center-left'
  | 'zoom-center-right'
  | 'zoom-top-start'
  | 'zoom-top'
  | 'zoom-top-end'
  | 'zoom-bottom-start'
  | 'zoom-bottom'
  | 'zoom-bottom-end'
  | 'zoom-left-start'
  | 'zoom-left'
  | 'zoom-left-end'
  | 'zoom-right-start'
  | 'zoom-right'
  | 'zoom-right-end'
  | 'slide-up'
  | 'slide-down';

export type TransitionProps = {
  /** Animation prefix */
  prefix?: string;

  /** Preset animation name */
  animation?: AnimationName;

  /** Prevent the transition conflict with the inner component */
  wrapper?: boolean;
  children?: React.ReactNode;
} & Partial<CSSTransitionProps>;

const Transition = (props: TransitionProps): React.ReactElement => {
  const {
    timeout = 300,
    unmountOnExit = true,
    appear = true,
    prefix = 'ty',
    animation,
    classNames,
    children,
    wrapper: _wrapper,
    addEndListener: _addEndListener,
    ...otherProps
  } = props;

  const nodeRef = useRef<HTMLDivElement>(null);

  const cssTransitionProps = {
    ...otherProps,
    nodeRef,
    timeout,
    appear,
    unmountOnExit,
    classNames: classNames ? classNames : `${prefix}-${animation}`,
  } as unknown as CSSTransitionProps;

  return (
    <CSSTransition {...cssTransitionProps}>
      <div ref={nodeRef}>{children}</div>
    </CSSTransition>
  );
};

Transition.displayName = 'Transition';

export default Transition;
